import{_ as e,v as o,b as a,R as d}from"./chunks/framework.caa0fbaf.js";const b=JSON.parse('{"title":"DOM 概述","description":"","frontmatter":{},"headers":[],"relativePath":"guide/JavaScript/WebApi/01/01_00.md","filePath":"guide/JavaScript/WebApi/01/01_00.md","lastUpdated":1656648142000}'),c={name:"guide/JavaScript/WebApi/01/01_00.md"},l=d('<div class="tip custom-block"><p class="custom-block-title">参考资料</p><ul><li><a href="https://wangdoc.com/javascript/" target="_blank" rel="noreferrer">阮一峰 JavaScript 教程</a></li></ul></div><h1 id="dom-概述" tabindex="-1">DOM 概述 <a class="header-anchor" href="#dom-概述" aria-label="Permalink to &quot;DOM 概述&quot;">​</a></h1><h2 id="_1-dom" tabindex="-1">1. DOM <a class="header-anchor" href="#_1-dom" aria-label="Permalink to &quot;1. DOM&quot;">​</a></h2><h3 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h3><ol><li><code>DOM</code> 是 <code>JavaScript</code> 操作网页的接口，全称为“文档对象模型”<code>Document Object Model</code>。</li><li>浏览器会根据 <code>DOM</code> 模型，将结构化文档比如 <code>HTML</code> 和 <code>XML</code> 解析成一系列的节点，再由这些节点组成一个树状结构<code>DOM Tree</code>，所有的节点都有规范的对外接口。</li></ol><h3 id="dom-作用" tabindex="-1">DOM 作用 <a class="header-anchor" href="#dom-作用" aria-label="Permalink to &quot;DOM 作用&quot;">​</a></h3><ol><li>它的作用是将网页转为一个 <code>JavaScript</code> 对象，从而可以用脚本进行各种操作比如增删内容。</li><li><code>DOM</code> 操作是 <code>JavaScript</code> 最常见的任务，离开了 <code>DOM</code>，<code>JavaScript</code> 就无法控制网页。另一方面，<code>JavaScript</code> 也是最常用于 <code>DOM</code> 操作的语言。</li></ol><h2 id="_2-节点" tabindex="-1">2. 节点 <a class="header-anchor" href="#_2-节点" aria-label="Permalink to &quot;2. 节点&quot;">​</a></h2><h3 id="简介-1" tabindex="-1">简介 <a class="header-anchor" href="#简介-1" aria-label="Permalink to &quot;简介&quot;">​</a></h3><ol><li><code>DOM</code> 的最小组成单位叫做节点<code>node</code>。文档的树形结构 <code>DOM</code> 树，就是由各种不同类型的节点组成。</li></ol><h3 id="七种节点的类型" tabindex="-1">七种节点的类型： <a class="header-anchor" href="#七种节点的类型" aria-label="Permalink to &quot;七种节点的类型：&quot;">​</a></h3><ol><li><p><code>Document</code>：文档节点，整个文档树的顶层节点。</p></li><li><p><code>DocumentType</code>：文档类型声明节点，<code>doctype</code>标签比如<code>&lt;!DOCTYPE html&gt;</code>。</p></li><li><p><code>Element</code>： 元素节点，网页的各种<code>HTML</code>标签节点，比如<code>&lt;body&gt;</code>、<code>&lt;a&gt;</code>等。</p></li><li><p><code>Attr</code>：属性节点，网页元素的属性比如 <code>class=&quot;right&quot;</code>。</p></li><li><p><code>Text</code>：文本节点，标签之间或标签包含的文本。</p></li><li><p><code>Comment</code>：注释节点。</p></li><li><p><code>DocumentFragment</code>：文档的片段节点。</p></li><li><p>浏览器提供一个原生的节点对象<code>Node</code>，上面这七种节点都继承了<code>Node</code>，因此具有一些共同的属性和方法。</p></li></ol><h2 id="_3-节点树" tabindex="-1">3. 节点树 <a class="header-anchor" href="#_3-节点树" aria-label="Permalink to &quot;3. 节点树&quot;">​</a></h2><h3 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h3><ol><li>一个文档的所有节点，按照所在的层级，可以抽象成一种树状结构。这种树状结构就是 <code>DOM</code> 树。</li><li>节点树有一个顶层节点，下一层都是顶层节点的子节点，然后子节点又有自己的子节点，就这样层层衍生出一个金字塔结构，又像一棵树。</li><li>浏览器原生提供<code>document</code>节点，代表整个文档，文档的第一层有两个节点：</li></ol><ul><li>第一个是文档类型节点<code>&lt;!doctype html&gt;</code></li><li>第二个是 <code>HTML</code> 网页的顶层容器标签<code>&lt;html&gt;</code>，他是树结构的根节点<code>root node</code>，其他 <code>HTML</code> 标签节点都是它的下级节点。</li></ul><h3 id="节点间的关系" tabindex="-1">节点间的关系 <a class="header-anchor" href="#节点间的关系" aria-label="Permalink to &quot;节点间的关系&quot;">​</a></h3><ol><li>除了根节点，其他节点都有三种层级关系。</li><li>父节点关系<code>parentNode</code>：直接的那个上级节点。</li><li>子节点关系<code>childNodes</code>：直接的下级节点。</li><li>同级节点关系<code>sibling</code>：拥有同一个父节点的节点。</li></ol>',18),i=[l];function t(r,h,n,s,p,u){return o(),a("div",null,i)}const _=e(c,[["render",t]]);export{b as __pageData,_ as default};
